mapper.select:
SELECT ID, POST_TITLE, POST_CONTENT ,POST_READ_COUNT, POST_CREATE_AT, POST_TAG, POST_PROFILE, USER_ID, USER_NICKNAME, USER_PROFILE, NVL(LIKE_COUNT, 0) AS LIKE_COUNT, NVL(COMMENT_COUNT, 0) AS COMMENT_COUNT FROM VW_POST_SUMMARY WHERE POST_IS_DELETED = 0
AND POST_TAG = #{postTag}
ORDER BY ID DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

mapper.update:
UPDATE TBL_POST
SET POST_TITLE = #{postTitle}, POST_CONTENT = #{postContent}, POST_TAG = #{postTag}
WHERE ID = #{id} AND USER_ID = #{userId}

UPDATE TBL_POST
SET POST_READ_COUNT = POST_READ_COUNT + 1
WHERE ID = #{id}

UPDATE TBL_POST
SET POST_IS_DELETED = 1
WHERE ID = #{id} AND USER_ID = #{userId}
